1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const COMPONENT_BLOCK_PREMIUM = 60;
4	
5	const MAIN_ITEM_PREMIUMS: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	};
11	
12	const COMPONENT_PREMIUMS: Record<string, number> = {
13	  rune: 25,
14	  moonstone: 25,
15	};
16	
17	function calculateBasePremium(items: any[]): number {
18	  const componentCounts: Record<string, number> = {};
19	  let premium = 0;
20	  for (const item of items) {
21	    if (item.type in COMPONENT_PREMIUMS) {
22	      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
23	    } else {
24	      premium += MAIN_ITEM_PREMIUMS[item.type];
25	    }
26	  }
27	  for (const [type, count] of Object.entries(componentCounts)) {
28	    premium += count === 3 ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUMS[type];
29	  }
30	  return premium;
31	}
32	
33	const CURSED_SURCHARGE_RATE = 0.5;
34	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
35	const HIGH_ENCHANTMENT_THRESHOLD = 5;
36	const LOYALTY_DISCOUNT_RATE = 0.2;
37	const LOYALTY_YEARS_THRESHOLD = 2;
38	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
39	
40	function calculateSingleItemSurcharge(item: any): number {
41	  const basePremium = MAIN_ITEM_PREMIUMS[item.type] || 0;
42	  let surcharge = 0;
43	  if (item.cursed) {
44	    surcharge += basePremium * CURSED_SURCHARGE_RATE;
45	  }
46	  if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
47	    surcharge += basePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE;
48	  }
49	  return surcharge;
50	}
51	
52	function calculateItemSurcharges(items: any[]): number {
53	  return items.reduce((total, item) => total + calculateSingleItemSurcharge(item), 0);
54	}
55	
56	function calculatePolicyModifiers(basePremium: number, yearsWithMHPCO: number, quoteIndex: number): number {
57	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
58	  const loyaltyDiscount = yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
59	  const followUpDiscount = quoteIndex > 0 ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
60	  return firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount;
61	}
62	
63	function calculateQuotePremium(items: any[], yearsWithMHPCO: number, quoteIndex: number): number {
64	  const basePremium = calculateBasePremium(items);
65	  const itemSurcharges = calculateItemSurcharges(items);
66	  const policyModifiers = calculatePolicyModifiers(basePremium, yearsWithMHPCO, quoteIndex);
67	  return Math.ceil(basePremium + itemSurcharges + policyModifiers + PROCESSING_FEE);
68	}
